案例代码：
component MUX2x1 is		//一个非标准逻辑类型用于端口定义，端口应该是std_logic和std_logic_vector类型
port(
	d1: in std_logic_vector;
	d2: in std_logic_vector;
	sel: in bit;		//端口“sel”是一个非标准逻辑类型
	mout: out std_logic_vector
	);
end component;

案例代码：
entity DFF is		//实体“DFF”没有使用IEEE.std_logic_1164,RTL设计需要通过连接基本包来使用std_logic和std_logic_vector
	...
end DFF;
library ieee;
use ieee.std_logic_1164.all;
architecture RTL of DFF is
	...
end RTL;

案例代码-1：
entity DFF is		//实体“DFF”没有使用IEEE.std_logic_1164,RTL设计需要通过连接基本包来使用std_logic和std_logic_vector
	...
end DFF;
library ieee;
use ieee.std_logic_1164.all;
architecture RTL of DFF is
	...
end RTL;

案例代码：
entity top is                                  //在“top”例化中同时使用了相反沿触发器
port( clk, din : in std_logic;
	dout1, dout2 : out std_logic);
end entity;
architecture RTL of top is
begin
process(clk)                                  //时钟信号“clk”的所有上升沿和下降沿都被使用。不宜同时使用相反沿触发器
begin
if falling_edge(clk) then
	dout1 <= din;
end if;
end process;
process(clk)
begin
if rising_edge(clk) then
dout2 <= din;
end if;
end process;
end;

	案例代码：
	process (g_op, a, b, c) begin
    if(g_op) then 	
	  y <= a and b and c;  //可能会生成锁存器。
	end if;
	end process;

案例代码：
entity top is
port (
CLK, CTRL, D1, D2: in std_logic;
OUT1 : out std_logic;
OUT2 : out std_logic
);
end entity;

architecture basic of top is
signal and_clk : std_logic;
begin
	DFF1 : entity dff port map ( CLK => and_clk, D => D1, Q => OUT1 );
	DFF2 : entity dff port map ( CLK => CLK, D => D2, Q => OUT2 );
	and_clk <= CTRL and CLK;		//全局时钟“CLK”通过了门控，只要有可能就不要将门控时钟用在FPGA中，因为这样的设计进行时钟延迟和偏斜的细调会变得很困难
end architecture;

案例代码：
architecture Behavioral of top is
   component add_rst
	  port( 
		clk             :in  std_logic;
		rst_1            :in  std_logic; 
		rst_2            :in  std_logic;		  
		rst_o            :out std_logic
	   );
  end component;
begin
 r1: add_rst PORT MAP(clk,rst_1,rst_2,rst_o);		//端口连接应通过名字描述连接
end Behavioral;

案例代码：
process ( D1, D2 ) begin //敏感信号列表不完整，可能会存在RTL 和综合后仿真的差异。
if (SEL = '0') then //信号SEL 被读取，但未在敏感信号列表中。
  Q <= D1;
else
  Q <= D2;
end if;
end process;

案例代码：
entity top is                                  
port( clk, din : in std_logic;
	dout1, dout2 : out std_logic);
end entity;
architecture RTL of top is
begin
process(clk)                                  
begin
if falling_edge(clk) then
	dout1 <= din;
end if;
end process;
process(clk)
begin
if rising_edge(clk) then            //同时使用了同一时钟的上升沿和下降沿
dout2 <= din;
end if;
end process;
end;

案例代码：
process (clk, reset, set) begin //触发器q引用了两个异步置位和异步复位控制。推荐使用单独的异步复位控制。
if ( reset = '1' ) then   //异步复位控制。
  q <= '0';
elsif ( set= '1' ) then   //异步置位控制。
  q <= '1';
elsif ( clk'event and clk = '1' ) then
  q <= data;
endif;
end process;
